import Model from 'flarum/common/Model';
export default class Team extends Model {
  name = (() => Model.attribute('name'))();
  slug = (() => Model.attribute('slug'))();
  abbreviation = (() => Model.attribute('abbreviation'))();
  conference = (() => Model.attribute('conference'))();
  cfbdId = (() => Model.attribute('cfbdId'))();
  espnId = (() => Model.attribute('espnId'))();
  logoPath = (() => Model.attribute('logoPath'))();
  logoDarkPath = (() => Model.attribute('logoDarkPath'))();
  logoCustom = (() => Model.attribute('logoCustom'))();
  logoUrl = (() => Model.attribute('logoUrl'))();
  logoDarkUrl = (() => Model.attribute('logoDarkUrl'))();
}
flarum.reg.add('ernestdefoe-picks', 'common/models/Team', Team);